/**
 * Effects Module
 * Handles button hover effects, text animations, scroll button hover effects, and mobile menu
 */
(function() {
  'use strict';
  
  // Initialize Portfolio namespace
  window.Portfolio = window.Portfolio || {};
  
  /**
   * Setup button hover effects
   */
  function setupButtonEffects() {
    document.querySelectorAll('.btn').forEach(button => {
      button.addEventListener('mouseenter', e => {
        button.classList.remove('radial-hover');
        
        const rect = button.getBoundingClientRect();
        const x = ((e.clientX - rect.left) / rect.width) * 100;
        const y = ((e.clientY - rect.top) / rect.height) * 100;
        
        button.style.setProperty('--x', `${x}%`);
        button.style.setProperty('--y', `${y}%`);
        button.classList.add('radial-hover');
      });
      
      button.addEventListener('mousemove', e => {
        const rect = button.getBoundingClientRect();
        const x = ((e.clientX - rect.left) / rect.width) * 100;
        const y = ((e.clientY - rect.top) / rect.height) * 100;
        
        button.style.setProperty('--x', `${x}%`);
        button.style.setProperty('--y', `${y}%`);
      });
      
      button.addEventListener('mouseleave', () => {
        button.classList.remove('radial-hover');
      });
    });
  }
  
  /**
   * Setup mobile menu
   */
  function setupMobileMenu() {
    const burgerIcon = document.getElementById('burgerIcon');
    const menu = document.querySelector('.menu-wrapper ul.menu');
    const menuOverlay = document.getElementById('menuOverlay');
    
    if (!burgerIcon || !menu || !menuOverlay) return;
    
    burgerIcon.addEventListener('click', () => {
      menu.classList.toggle('active');
      menuOverlay.classList.toggle('active');
      burgerIcon.classList.toggle('active');
    });
    
    menuOverlay.addEventListener('click', () => {
      menu.classList.remove('active');
      menuOverlay.classList.remove('active');
      burgerIcon.classList.remove('active');
    });
    
    menu.querySelectorAll('a').forEach(link => {
      link.addEventListener('click', () => {
        menu.classList.remove('active');
        menuOverlay.classList.remove('active');
        burgerIcon.classList.remove('active');
      });
    });
  }
  
  /**
   * Setup text animations (Splitting.js)
   */
  function setupTextAnimations() {
    // Ensure Splitting.js is loaded
    if (typeof Splitting !== 'function') return;
    
    // "Hi" Letter 'i' Flip Animation
    const hiElement = document.querySelector('.headline h1[data-splitting]');
    if (hiElement) {
      const iCharSpan = hiElement.querySelector('.char[style*="--char-index:1"]');
      if (iCharSpan) {
        gsap.set(iCharSpan, { transformOrigin: "center center", transformPerspective: 400 });
        
        hiElement.addEventListener('mouseenter', () => {
          gsap.to(iCharSpan, {
            rotationY: "+=1080",
            duration: 0.7,
            ease: "elastic.out(1, 0.5)",
            overwrite: 'auto'
          });
        });
      }
    }
    
    // "Life" Pulse Animation
    document.querySelectorAll('[data-splitting][data-life-pulse]').forEach(element => {
      const lifeWord = element.querySelector('.word[data-word="life"]');
      if (!lifeWord) return;
      
      const chars = lifeWord.querySelectorAll('.char');
      if (!chars.length) return;
      
      gsap.set(chars, { transformOrigin: "center center" });
      
      const timeline = gsap.timeline({ paused: true, repeat: -1 });
      timeline.to(chars, {
        scale: 1.05,
        duration: 0.15,
        stagger: 0.05,
        ease: "power2.inOut",
        yoyo: true,
        repeat: 1
      });
      
      lifeWord.addEventListener('mouseenter', () => timeline.play());
      lifeWord.addEventListener('mouseleave', () => {
        timeline.pause().progress(0);
        gsap.set(chars, { scale: 1 });
      });
    });
  }
  
  /**
   * Setup scroll button hover effects - BULLETPROOF VERSION
   */
  function setupScrollButtonHoverEffects() {
    const scrollDownBtn = document.querySelector('.scroll-down');
    const scrollUpBtn = document.querySelector('.scroll-up');
    const scrollDownArrow = document.querySelector('.scroll-down .scroll-btn-arrow');
    const scrollUpArrow = document.querySelector('.scroll-up .scroll-btn-arrow');
    
    if (!scrollDownBtn || !scrollUpBtn || !scrollDownArrow || !scrollUpArrow) return;
    
    console.log('[SCROLL HOVER] BULLETPROOF setup starting');
    
    // NUCLEAR OPTION: Kill ALL animations on these elements
    gsap.killTweensOf([scrollDownArrow, scrollUpArrow]);
    
    // Disable ALL CSS
    gsap.set([scrollDownArrow, scrollUpArrow], {
      transition: "none",
      animation: "none"
    });
    
    scrollDownArrow.style.animation = 'none';
    scrollUpArrow.style.animation = 'none';
    scrollDownArrow.style.transition = 'none';
    scrollUpArrow.style.transition = 'none';
    
    // Set base positions
    gsap.set(scrollDownArrow, {
      transform: "translate(-50%, -50%) translateY(35px)"
    });
    
    gsap.set(scrollUpArrow, {
      transform: "translate(-50%, -50%) translateY(-35px) rotate(180deg)"
    });
    
    // Global timeline references - OUTSIDE event handlers
    let downTimeline = null;
    let upTimeline = null;
    
    // SCROLL DOWN
    scrollDownBtn.addEventListener('mouseenter', () => {
      console.log('[DOWN] ENTER');
      
      // NUCLEAR KILL everything first
      gsap.killTweensOf(scrollDownArrow);
      if (downTimeline) {
        downTimeline.kill();
        downTimeline = null;
      }
      
      // Create new timeline
      downTimeline = gsap.timeline({ repeat: -1, yoyo: true });
      downTimeline.to(scrollDownArrow, {
        transform: "translate(-50%, -50%) translateY(30px)",
        duration: 0.5,
        ease: "power2.inOut"
      }).to(scrollDownArrow, {
        transform: "translate(-50%, -50%) translateY(35px)",
        duration: 0.5,
        ease: "power2.inOut"
      });
    });
    
    scrollDownBtn.addEventListener('mouseleave', () => {
      console.log('[DOWN] LEAVE');
      
      // NUCLEAR KILL everything
      gsap.killTweensOf(scrollDownArrow);
      if (downTimeline) {
        downTimeline.kill();
        downTimeline = null;
      }
      
      // Return to base
      gsap.to(scrollDownArrow, {
        transform: "translate(-50%, -50%) translateY(35px)",
        duration: 0.4,
        ease: "power2.out",
        overwrite: true
      });
    });
    
    // SCROLL UP
    scrollUpBtn.addEventListener('mouseenter', () => {
      console.log('[UP] ENTER');
      
      // NUCLEAR KILL everything first
      gsap.killTweensOf(scrollUpArrow);
      if (upTimeline) {
        upTimeline.kill();
        upTimeline = null;
      }
      
      // Create new timeline
      upTimeline = gsap.timeline({ repeat: -1, yoyo: true });
      upTimeline.to(scrollUpArrow, {
        transform: "translate(-50%, -50%) translateY(-30px) rotate(180deg)",
        duration: 0.5,
        ease: "power2.inOut"
      }).to(scrollUpArrow, {
        transform: "translate(-50%, -50%) translateY(-25px) rotate(180deg)",
        duration: 0.5,
        ease: "power2.inOut"
      });
    });
    
    scrollUpBtn.addEventListener('mouseleave', () => {
      console.log('[UP] LEAVE');
      
      // NUCLEAR KILL everything
      gsap.killTweensOf(scrollUpArrow);
      if (upTimeline) {
        upTimeline.kill();
        upTimeline = null;
      }
      
      // Return to base
      gsap.to(scrollUpArrow, {
        transform: "translate(-50%, -50%) translateY(-35px) rotate(180deg)",
        duration: 0.4,
        ease: "power2.out",
        overwrite: true
      });
    });
    
    console.log('[SCROLL HOVER] BULLETPROOF setup complete');
  }
  
  // Expose effects functions
  window.Portfolio.effects = {
    setupButtonEffects,
    setupMobileMenu,
    setupTextAnimations,
    setupScrollButtonHoverEffects
  };
  
  if (window.Portfolio.debug) {
    console.log('[EFFECTS] Module loaded successfully');
  }
})(); 